sql:
SELECT response_text
FROM dialogue_lines
WHERE voice_type = 'Standard';

SELECT COUNT(DISTINCT line_id) 
FROM dialogue_lines 
WHERE quest = 'Defeat the Dragon';

SELECT race, COUNT(*) AS line_count
FROM dialogue_lines
GROUP BY race;

SELECT COUNT(*) AS total_dialogue_lines
FROM dialogue_lines
WHERE category = 'Scene' AND type = 'SceneDialogue';

SELECT s.speaker_name, s.race
FROM speakers s
INNER JOIN dialogue_lines d ON s.speaker_name = d.speaker;

external_knowledge:
- 'whispers' metaphorically refer to the voice files;
- 'digital archives' metaphorically refer to the database containing the voice files;
- 'closest to today’s date' refers to the most recent upload_date.

sql:
SELECT response_text
FROM dialogue_lines
ORDER BY line_id;

SELECT npcs.npc_name, voice_actors.actor_name
FROM npcs
JOIN voice_actors ON npcs.voice_actor_id = voice_actors.voice_actor_id;

SELECT AVG(LENGTH(response_text)) AS average_response_length
FROM dialogue_lines
WHERE quest = 'specific_quest_id';
